const r=t=>String(t||"").toUpperCase(),f=t=>{const e=String(t||"").replace(/\D/g,"");return e.length===0?"":e.length<=3?e:e.length<=6?`${e.slice(0,3)}-${e.slice(3)}`:`${e.slice(0,3)}-${e.slice(3,6)}-${e.slice(6,10)}`},s=t=>String(t||"").replace(/[^A-Z0-9]/g,""),g=t=>{const e=String(t||"").replace(/\D/g,"");return e?e.slice(-4):""},p=(t,e,l,a="")=>{const i=s(r(t)),c=s(r(e)),n=g(l);if(n==="")return"";if(i!==""&&c!=="")return`${i.slice(0,3)}${c.slice(0,3)}${n}`.toUpperCase();const o=s(r(a));return o!==""?`${o.slice(0,6)}${n}`.toUpperCase():""};export{f,p as g,r as n};
